    'news.eyebrow':   { en: 'News', nl: 'Nieuws', fr: 'Actualités', de: 'Aktuelles', it: 'Notizie', es: 'Noticias', zh: '新闻', ja: 'ニュース' },
    'news.body':      { en: 'The latest from Minerva — announcements, milestones and press. The newsroom opens with our next announcement.', nl: 'Het laatste van Minerva — aankondigingen, mijlpalen en pers. De newsroom opent met onze volgende aankondiging.', fr: 'Les dernières nouvelles de Minerva — annonces, jalons et presse. La salle de presse ouvrira avec notre prochaine annonce.', de: 'Das Neueste von Minerva — Ankündigungen, Meilensteine und Presse. Der Newsroom öffnet mit unserer nächsten Ankündigung.', it: 'Le ultime da Minerva — annunci, traguardi e stampa. La newsroom aprirà con il nostro prossimo annuncio.', es: 'Lo último de Minerva — anuncios, hitos y prensa. La sala de prensa abrirá con nuestro próximo anuncio.', zh: 'Minerva 的最新动态 — 公告、里程碑与媒体。新闻中心将随我们的下一则公告开启。', ja: 'Minerva の最新情報 — 発表、節目、報道。ニュースルームは次の発表とともに公開されます。' },
