    /* ---------- investors ---------- */
    'inv.eyebrow':    { en: 'Investor Relations', nl: 'Investeerdersrelaties', fr: 'Relations investisseurs', de: 'Investor Relations', it: 'Relazioni con gli investitori', es: 'Relación con inversores', zh: '投资者关系', ja: '投資家情報' },
    'inv.body1':      { en: "Minerva is reawakening one of Europe's great marques — uniting Belgian heritage with Formula 1 engineering across a sequenced programme of three motor cars: the Aegis Racing, the Aegis GT and the Sovereign.", nl: 'Minerva doet een van de grote Europese merken herleven — Belgisch erfgoed verenigd met Formule 1-techniek in een gefaseerd programma van drie auto’s: de Aegis Racing, de Aegis GT en de Sovereign.', fr: "Minerva fait renaître l'une des grandes marques européennes — alliant l'héritage belge à l'ingénierie de Formule 1 à travers un programme séquencé de trois automobiles : l'Aegis Racing, l'Aegis GT et la Sovereign.", de: 'Minerva erweckt eine der großen europäischen Marken neu — belgisches Erbe vereint mit Formel-1-Technik in einem gestaffelten Programm aus drei Automobilen: Aegis Racing, Aegis GT und Sovereign.', it: 'Minerva fa rivivere uno dei grandi marchi europei — unendo il patrimonio belga all’ingegneria di Formula 1 in un programma articolato di tre vetture: Aegis Racing, Aegis GT e Sovereign.', es: 'Minerva revive una de las grandes marcas europeas — uniendo el patrimonio belga con la ingeniería de Fórmula 1 en un programa secuenciado de tres automóviles: el Aegis Racing, el Aegis GT y el Sovereign.', zh: 'Minerva 正在唤醒欧洲伟大品牌之一 — 将比利时传承与一级方程式工程融为一体，分阶段推出三款座驾：Aegis Racing、Aegis GT 与 Sovereign。', ja: 'Minerva は欧州の名門ブランドのひとつを再興します — ベルギーの伝統と F1 のエンジニアリングを融合し、Aegis Racing、Aegis GT、Sovereign の3台を段階的に展開します。' },
    'inv.body2':      { en: 'We are inviting a select circle of aligned partners to take part in this revival. To request the investment dossier and arrange a confidential conversation, write to us.', nl: 'Wij nodigen een selecte kring van gelijkgestemde partners uit om aan deze heropleving deel te nemen. Schrijf ons voor het investeringsdossier en een vertrouwelijk gesprek.', fr: 'Nous invitons un cercle restreint de partenaires partageant notre vision à participer à ce renouveau. Pour demander le dossier d’investissement et organiser un entretien confidentiel, écrivez-nous.', de: 'Wir laden einen ausgewählten Kreis gleichgesinnter Partner ein, an dieser Wiederbelebung teilzunehmen. Für das Investitionsdossier und ein vertrauliches Gespräch schreiben Sie uns.', it: 'Invitiamo una cerchia selezionata di partner allineati a partecipare a questa rinascita. Per richiedere il dossier d’investimento e fissare un colloquio riservato, scriveteci.', es: 'Invitamos a un círculo selecto de socios afines a participar en este renacimiento. Para solicitar el dossier de inversión y concertar una conversación confidencial, escríbenos.', zh: '我们诚邀理念一致的少数合作伙伴参与此次复兴。如需获取投资文件并安排保密洽谈，请来函联系。', ja: '私たちは志を同じくする選ばれたパートナーをこの復興にお招きします。投資資料のご請求と機密のご相談は、メールにてご連絡ください。' },

    /* ---------- press ---------- */
    'press.eyebrow':  { en: 'Press', nl: 'Pers', fr: 'Presse', de: 'Presse', it: 'Stampa', es: 'Prensa', zh: '媒体', ja: '報道' },
    'press.body':     { en: 'For press enquiries, accreditation and media assets relating to the re-launch of Minerva, please contact our press office.', nl: 'Voor persvragen, accreditatie en mediamateriaal over de herlancering van Minerva kunt u contact opnemen met ons persbureau.', fr: 'Pour toute demande presse, accréditation ou ressources médias liées au renouveau de Minerva, contactez notre service de presse.', de: 'Für Presseanfragen, Akkreditierung und Medienmaterial zur Wiederbelebung von Minerva wenden Sie sich an unsere Pressestelle.', it: 'Per richieste stampa, accrediti e materiali media sul rilancio di Minerva, contatta il nostro ufficio stampa.', es: 'Para consultas de prensa, acreditación y recursos para medios sobre el relanzamiento de Minerva, contacta con nuestra oficina de prensa.', zh: '有关 Minerva 重启的媒体咨询、采访申请及媒体素材，请联系我们的新闻办公室。', ja: 'Minerva の復活に関する報道のお問い合わせ、取材申請、メディア素材については、広報部までご連絡ください。' },
    'press.tag':      { en: 'Press kit — coming soon', nl: 'Perskit — binnenkort', fr: 'Dossier de presse — bientôt', de: 'Pressemappe — in Kürze', it: 'Press kit — prossimamente', es: 'Kit de prensa — próximamente', zh: '新闻资料包 — 即将推出', ja: 'プレスキット — まもなく' },

